(function () { var g = window.GrowthPilot = window.GrowthPilot || {}; var s = document.currentScript; g.pixelKey = s && s.getAttribute('data-key') || ''; g.endpoint = 'https://fetchbot.ai/api/v1/track/'; function t(e, d) { var p = { pixel_key: g.pixelKey, event_type: e, url: window.location.href, referrer: document.referrer, timestamp: new Date().toISOString(), user_agent: navigator.userAgent, screen_width: screen.width, screen_height: screen.height, viewport_width: window.innerWidth, viewport_height: window.innerHeight, language: navigator.language }; if (d) for (var k in d) p[k] = d[k]; try { navigator.sendBeacon(g.endpoint + 'event/', JSON.stringify(p)) } catch (ex) { var x = new XMLHttpRequest(); x.open('POST', g.endpoint + 'event/', true); x.setRequestHeader('Content-Type', 'application/json'); x.send(JSON.stringify(p)) } } g.track = t; t('pageview'); window.addEventListener('beforeunload', function () { var dur = Math.round((Date.now() - g._start) / 1000); t('session_end', { duration: dur }) }); g._start = Date.now() })();
